pub fn size_prefixed_root_as_lms_with_opts<'b, 'o>(
  opts: &'o ::flatbuffers::VerifierOptions,
  buf: &'b [u8],
) -> Result<LMS<'b>, ::flatbuffers::InvalidFlatbuffer> {
  ::flatbuffers::size_prefixed_root_with_opts::<LMS<'b>>(opts, buf)
}
#[inline]
/// Assumes, without verification, that a buffer of bytes contains a LMS and returns it.
/// # Safety
/// Callers must trust the given bytes do indeed contain a valid `LMS`.
pub unsafe fn root_as_lms_unchecked(buf: &[u8]) -> LMS<'_> {
  unsafe { ::flatbuffers::root_unchecked::<LMS>(buf) }
}
#[inline]
/// Assumes, without verification, that a buffer of bytes contains a size prefixed LMS and returns it.
/// # Safety
/// Callers must trust the given bytes do indeed contain a valid size prefixed `LMS`.
pub unsafe fn size_prefixed_root_as_lms_unchecked(buf: &[u8]) -> LMS<'_> {
  unsafe { ::flatbuffers::size_prefixed_root_unchecked::<LMS>(buf) }
}
pub const LMS_IDENTIFIER: &str = "$LMS";

#[inline]
pub fn lms_buffer_has_identifier(buf: &[u8]) -> bool {
  ::flatbuffers::buffer_has_identifier(buf, LMS_IDENTIFIER, false)
}

#[inline]
pub fn lms_size_prefixed_buffer_has_identifier(buf: &[u8]) -> bool {
  ::flatbuffers::buffer_has_identifier(buf, LMS_IDENTIFIER, true)
}

#[inline]
pub fn finish_lms_buffer<'a, 'b, A: ::flatbuffers::Allocator + 'a>(
    fbb: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>,
    root: ::flatbuffers::WIPOffset<LMS<'a>>) {
  fbb.finish(root, Some(LMS_IDENTIFIER));
}

#[inline]
pub fn finish_size_prefixed_lms_buffer<'a, 'b, A: ::flatbuffers::Allocator + 'a>(fbb: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>, root: ::flatbuffers::WIPOffset<LMS<'a>>) {
  fbb.finish_size_prefixed(root, Some(LMS_IDENTIFIER));
}
